content.m_query_monthly_with_date_extraction:
// Full M query: SharePoint folder + combine CSVs + extract year/month from filename
// Assumes filenames like report_2024_01.csv
let
    // ── 1. Connect to SharePoint ──────────────────────────────────────────
    Source = SharePoint.Files("https://contoso.sharepoint.com/sites/MySite", [ApiVersion=15]),

    // ── 2. Filter to target folder ───────────────────────────────────────
    FilteredFolder = Table.SelectRows(Source, each Text.Contains([Folder Path], "/Shared Documents/Monthly-Reports/")),

    // ── 3. Keep only .csv files ──────────────────────────────────────────
    CSVOnly = Table.SelectRows(FilteredFolder, each [Extension] = ".csv"),

    // ── 4. Capture filename before expanding ─────────────────────────────
    AddFilename = Table.AddColumn(CSVOnly, "SourceFile", each [Name], type text),

    // ── 5. Extract Year from filename (chars 7-10 in "report_2024_01.csv")
    AddYear = Table.AddColumn(AddFilename, "FileYear", each Number.FromText(Text.Middle([SourceFile], 7, 4)), Int64.Type),

    // ── 6. Extract Month from filename (chars 12-13)
    AddMonth = Table.AddColumn(AddYear, "FileMonth", each Number.FromText(Text.Middle([SourceFile], 12, 2)), Int64.Type),

    // ── 7. Parse each CSV binary ──────────────────────────────────────────
    ParseCSV = Table.AddColumn(AddMonth, "ParsedCSV",
        each Csv.Document([Content], [
            Delimiter = ",",
            Columns = null,
            Encoding = 65001,
            QuoteStyle = QuoteStyle.None
        ])
    ),

    // ── 8. Promote headers in each parsed table ───────────────────────────
    PromoteHeaders = Table.TransformColumns(ParseCSV, {
        "ParsedCSV", each Table.PromoteHeaders(_, [PromoteAllScalars=true])
    }),

    // ── 9. Get column names from first file (all files must share schema)
    SampleColumns = Table.ColumnNames(PromoteHeaders{0}[ParsedCSV]),

    // ── 10. Expand all CSV rows into main table ───────────────────────────
    Expanded = Table.ExpandTableColumn(PromoteHeaders, "ParsedCSV", SampleColumns),

    // ── 11. Build a proper Date column from Year + Month (use 1st of month)
    AddDateColumn = Table.AddColumn(Expanded, "MonthDate", each #date([FileYear], [FileMonth], 1), type date),

    // ── 12. Remove columns no longer needed ───────────────────────────────
    Cleaned = Table.RemoveColumns(AddDateColumn, {"Content", "Extension", "Date accessed", "Date modified", "Date created", "Attributes", "Folder Path"}),

    // ── 13. Set data types ─────────────────────────────────────────────────
    // Replace col1, col2 with your actual CSV column names
    TypedTable = Table.TransformColumnTypes(Cleaned, {
        {"SourceFile",  type text},
        {"FileYear",    Int64.Type},
        {"FileMonth",   Int64.Type},
        {"MonthDate",   type date}
        // add your CSV column types here, e.g. {"Amount", Currency.Type}
    })
in
    TypedTable

