incremental_refresh.rangestart_rangeend_file_filter_example:
// Incremental refresh approach for SharePoint folder:
// Add two parameters: RangeStart (DateTime) and RangeEnd (DateTime)
// Then filter CSVOnly by the extracted FileYear/FileMonth falling within the range:

FilterByDateRange = Table.SelectRows(CSVOnly, each
    let
        // Build a date from the filename
        yr = Number.FromText(Text.Middle([Name], 7, 4)),
        mo = Number.FromText(Text.Middle([Name], 12, 2)),
        fileDate = #date(yr, mo, 1)
    in
        fileDate >= Date.From(RangeStart) and fileDate < Date.From(RangeEnd)
)
